window.__QUIZ_DATA__=[{"id":"objective>Geography>2024>1","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question      What is the scale of the map in statement form?","images":["data:image/png;base64,"],"options":{"A":"1 centimetre on the map represents 2 kilometres on the ground","B":"1 centimetre on the map represents 1 kilometre on the ground","C":"1 centimetre on the map represents 1/2 kilometre on the ground","D":"1 centimetre on the map represents 1/4 kilometre on the ground"},"answer":"C","explanation":"The scale of the map in statement form is 1 centimetre on the map represents 1/2 kilometre on the ground","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>2","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    The contour interval on the mapped area is","images":["data:image/png;base64,"],"options":{"A":"50 metres","B":"100 metres","C":"150 metres","D":"200 metres"},"answer":"A","explanation":"Looking at this contour interval refers to the difference in elevation between two consecutive contour lines on a topographic map. It is the vertical distance between two adjacent contour lines, representing a consistent change in elevation. Therefore, the contour interval on the mapped area is 50 metre.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>3","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    The feature at the mouth of River Bala is likely to be a","images":["data:image/png;base64,"],"options":{"A":"waterfall","B":"river capture","C":"saddle","D":"delta"},"answer":"D","explanation":"The feature at the mouth of River Bala is likely to be a delta. A delta  is a landform that forms at the mouth of a river, where the river deposits sediment and splits into multiple branches before emptying into a larger body of water, such as an ocean, sea or lake.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>4","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    What is the direction of Sasa from Moma?","images":["data:image/png;base64,"],"options":{"A":"North east","B":"South west","C":"North west","D":"South east"},"answer":"C","explanation":"The direction of Sasa from Moma is North west on the map","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>5","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    The highest point on the mapped area is approximately","images":["data:image/png;base64,"],"options":{"A":"325 metres","B":"375 metres","C":"390 metres","D":"395 metres"},"answer":"A","explanation":"The highest point on the mapped area is approximately 325 metres","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>6","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    The distance as the crow flies from Opom to Moma is approximately","images":["data:image/png;base64,"],"options":{"A":"4 kilometres","B":"6 kilometres","C":"12 kilometres","D":"16 kilometres"},"answer":"B","explanation":"The distance as the crow flies from Opom to Moma is approximately 6 kilometres","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>7","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    Which part of the mapped area can coastal fishing be practised?","images":["data:image/png;base64,"],"options":{"A":"South western","B":"South eastern","C":"North eastern","D":"North western"},"answer":"C","explanation":"Coastal fishing can be practised in the North Eastern part of the mapped area on the map because they are bays, mangrove swamps, sandy beaches.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>8","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    The feature marked Q on the mapped area can be described as","images":["data:image/png;base64,"],"options":{"A":"meander","B":"levee","C":"elbow of capture","D":"ox-bow lake"},"answer":"D","explanation":"The feature marked Q on the mapped area can be described as ox-bow lake. An ox-bow lake is a type of lake that forms when a meandering curve of a river is cut off from the main stream, creating a distinctive u-shaped body of water.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>9","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    Which of the following settlements is likely to engage in fish processing?","images":["data:image/png;base64,"],"options":{"A":"Lola","B":"Sasa","C":"Kako","D":"Opom"},"answer":"C","explanation":"The likely settlement to engage in fish processing is kako because it is near a sea.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>10","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of JOJA DISTRICT and use it to answer the question    What is the approximate bearing of Lola from Sasa?","images":["data:image/png;base64,"],"options":{"A":"63o","B":"154o","C":"206o","D":"334o"},"answer":"C","explanation":"The  approximated bearing of Lola from Sasa is 206o","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>11","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of Station F.Study and use it to answer the questions.  Station F  MonthJan.Feb.Mar.Apr.MayJun.Jul.Aug.Sep.Oct.Nov.Dec.Temperature(oC)232429343635333133322823Rainfall(mm)00010108133187201187500    The annual rainfall recorded at Station F is","images":[],"options":{"A":"831mm","B":"813 mm","C":"381 mm","D":"318 mm"},"answer":"A","explanation":"The annual rainfall recorded at Station F is 831mm, this is gotten from the table because when you add all the rainfalls of station F from January to December, the total rainfall is also the annual rainfall. Therefore, the summation of the rainfall throughout the year is 831mm.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>12","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of Station F.Study and use it to answer the questions.  Station F  MonthJan.Feb.Mar.Apr.MayJun.Jul.Aug.Sep.Oct.Nov.Dec.Temperature(oC)232429343635333133322823Rainfall(mm)00010108133187201187500  Which of the following months is the hottest?","images":[],"options":{"A":"January","B":"April","C":"May","D":"September"},"answer":"C","explanation":"The month with the highest temperature is the hottest. Therefore the hottest month is may because it has the highest temperature.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>13","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of Station F.Study and use it to answer the questions.  Station F  MonthJan.Feb.Mar.Apr.MayJun.Jul.Aug.Sep.Oct.Nov.Dec.Temperature(oC)232429343635333133322823Rainfall(mm)00010108133187201187500  What is the annual range of temperature for Station F?.","images":[],"options":{"A":"36 oC","B":"23 oC","C":"13 oC","D":"3 oC"},"answer":"A","explanation":"The annual range of temperature for station F is 36 oC.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>14","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following represents the correct sequence in which denudation occurs?","images":[],"options":{"A":"Weathering, erosion and deposition","B":"Erosion, weathering and deposition","C":"Weathering, deposition and erosion","D":"Deposition,erosion and weathering"},"answer":"A","explanation":"The correct sequence in which denudation occurs is weathering, erosion and deposition. The sequence is often remembering using the acronym \"WETD\".  W-Weathering, E-Erosion, T-Transportation, D-Deposition.  Denudation is the overall process of wearing away the earth's surface involving the combination of these four stages.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>15","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which drainage pattern is best formed in arcas of alternate hard and soft rocks?","images":[],"options":{"A":"Trellised","B":"Dendritic","C":"Radial","D":"Annular"},"answer":"A","explanation":"A trellised drainage pattern is characteristed by a network of streams and rivers that form a regular or grid-like pattern. Trellised drainage patterns are common in areas with alternating hard and soft rocks such as the Appalachian mountains in North America","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>16","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Rocks formed through cementation of accumulated materials under water is","images":[],"options":{"A":"metamorphic","B":"igneous","C":"sedimentary","D":"acidic"},"answer":"C","explanation":"Sedimentary rocks are formed through the cementation of accumulated materials such as mineral particles, organic matter and rock fragments, under water. Example of sedimentary rocks include conglomerates, sandstones, limestones, shales etc.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>17","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"An intrusion of thick acid lava which forces overlying sedimentary rock layers to bulge into a dome may cool and solidify to form a","images":[],"options":{"A":"batholith","B":"laccolith","C":"dyke","D":"Iopolith"},"answer":"B","explanation":"A laccolith is a type of igneous intrusion that forms when thick, acidic lava (such as granite or rhyolite) pushes up the overlying sedimentary rock layer causing them to bulge into a dome shape. As the lava cools and solidifies, it forms a flat-bottomed, sauce-shaped of igneous rock.  N.B: The term \"laccolith\" and \"Iopolith\" are sometimes used interchangeably but technically, a Iaccolith is formed from acidic rocks while a Iopolith is formed from acidic rocks while a Iopolith is formed from a basic crultrabasic rocks.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>18","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The Greek system of classifying climate is based on","images":[],"options":{"A":"temperature","B":"rainfall and temperature","C":"rainfall and vegetation","D":"humidity"},"answer":"B","explanation":"The greek word refers to the combination of rainfall and temperature in a particular region. This concept was later developed into a field of climatology, which studies the long term atmospheric condition in different areas","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>19","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"What will be the time at Greenwich meridian when it is 12 noon at longitude 60oE?","images":[],"options":{"A":"4.00 a.m","B":"4.00 p.m","C":"8.00 a.m","D":"8.00 p.m"},"answer":"B","explanation":"The time at greenwich meridian when it is 12noon at longitude 60oE is 4.00pm. Since greenwich is at 00 longitude  and the location at 600E is ahead of greenwich, you add the time difference.  60oE is equivalent to 1  60o x 4 minutes/o = 240 minutes  Convert this to hours:  240 minutes / 60 =4hours.  12 noon(GMT) + 4 hours = 4pm(GMT)  So, when it is 12noon at longitude 60oE the time at the greenwich meridian(0o longitude) would be 4pm","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>20","subject":"Geography","year":"2024","type":"Objective","topic":"THE SOLAR SYSTEM","question":"The movement of the earth around the sun on its elliptical orbit is called","images":[],"options":{"A":"rotation","B":"axis","C":"revolution","D":"gravitation"},"answer":"C","explanation":"The movement of the earth around the sun on its elliptical orbit is known as a revolution. Revolution refers to the complete rotation of an object around a larger body, such as a planet orbiting a star.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>21","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The Deccan plateau in India is a good example of","images":[],"options":{"A":"dissected plateau","B":"volcanic plateau","C":"tectonic plateau","D":"intermontane plateau"},"answer":"B","explanation":"The Deccan plateau in India is a good example of volcanic plateau. The Deccan plateau is a large volcanic plateau located in western and central India covering an area of approximately 500,000 square kilometers. Other examples of volcanic plateaus include the columbia plateau in North America and the Ethopian Highlands in Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>22","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Horst is a feature associated with","images":[],"options":{"A":"volcanic mountain","B":"residual mountain","C":"block mountain","D":"fold mountain"},"answer":"C","explanation":"Horst is a feature which is associated with block faulting. A horst is a type of geological structure that forms when a block of rock is uplifted along faults on both sides, creating a raised or elevated area.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>23","subject":"Geography","year":"2024","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS~~REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Which of the following pair of landforms are surface features of a karst region?  I. Clint  II. Grikes  III. Stalagmite  IV. Cavern","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"III and IV only"},"answer":"A","explanation":"Clint and grikes are surface features of karst regions. Karst regions are characterized by unique surface and underground features, formed through dissolution of soluble rocks like limestone, dolomite and gypsum.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>24","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Two towns, A and B are on the International Dateline, what would be the distance between the two towns if town A is located on latitude 40oN and town B is located on latitude 10oN?","images":[],"options":{"A":"8880 kilometres","B":"5550 kilometres","C":"3330 kilometres","D":"2220 kilometres"},"answer":"C","explanation":"Since both town are on international dateline(which is approximately 180o longitude), the distance between them can be calculated using the difference in their latitudes. The latitude difference between town A(40oN) and town B(10o) is 40oN and 10oN = 30o  Since 1o of latitude is approximately equal to 111km(69 miles), the distance between the two forms can be calculated as:  30o x 111km/o = 3330km  So, the distance between town A and town B is approximately 3330km(2067 miles).  N.B: This calculation assumes a spherical Earth and doesn't take into account the Earth's slightly ellipsodial shape or other geographical factors that might affect the exact distance.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>25","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Wind erosion results in the formation of the following landforms except","images":[],"options":{"A":"zeugen","B":"yardang","C":"ventifact","D":"barchan"},"answer":"A","explanation":"Zeugen is a landform created by glacial erosion, not wind erosion. It refers to a type of glacial erratic, a rock or boulder that has been transported by a glacier and deposited in a new location. The other options are all landforms created by wind erosion.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>26","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following best explains the breaking down of well jointed rocks into large rectangular shaped features by mechanical weathering?","images":[],"options":{"A":"Block disintegration","B":"Exfoliation dome","C":"Landslide","D":"Solufluction"},"answer":"A","explanation":"Block disintegration is a type of mechanical weathering that occurs when well-jointed rocks are broken down into large, rectangular shaped blocks or fragments.  N.B: Mechanical weathering involves physical forces breaking down rocks into smaller fragments, whereas chemical weathering involves chemical reactions altering the rocks composition.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>27","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following conditions can produce a waterfall?","images":[],"options":{"A":"A sharp break in the bed of a river","B":"Elbow of capture of young river","C":"Backward erosion","D":"Lateral erosion"},"answer":"A","explanation":"A waterfall is typically formed when a river flows over a steep, vertical or near-vertical drop in the riverbed known as a knickpoint. Note that waterfalls can also form due to other factors, such as glacial activity, volcanic activity or human intervention (e.g dam construction)","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>28","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Which of the following sequence is correct in the formation of a stack?","images":[],"options":{"A":"Cave, arch, headland, stack","B":"Headland, cave, arch, stack","C":"Headland, arch, cave, stack","D":"Cave, headland, arch, stack"},"answer":"B","explanation":"The correct sequence is Headland, cave, arch, stack. This sequence shows the progressive erosion of a headland by the sea, resulting in the formation of a stack.  N.B The other options are incorrect because they do not show the logical progression of erosion from a headland to stack.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>29","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"In which of the following regions will weathering by frost action occur throughout the year?","images":[],"options":{"A":"Cool temperate","B":"Equatorial","C":"Monsoon","D":"Mediterranean"},"answer":"A","explanation":"Frost action also known as frost weathering occurs when water seeps into cracks and crevices in rocks, freezes and expands, causing the rock to break apart. This process requires temperature to flunctuate above and below freezing point(0oC or 32oF).  N.B: Frost action can occur in other regions as well but its most persistent and effective in cool temperate regions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>30","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The normal lapse rate refers to the average rate at which","images":[],"options":{"A":"radiant energy is converted to heat","B":"air pressure decreases with altitude","C":"air pressure increases with altitude","D":"temperature decreases with altitude"},"answer":"D","explanation":"The lapse rate at which an atmospheric variable normally temperature in earth's atmosphere falls with altitude. For every 1 degree celsius there is a rise in altitude, the temperature decreases by 1oC. This is called normal lapse rate.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>31","subject":"Geography","year":"2024","type":"Objective","topic":"THE SOLAR SYSTEM","question":"Which of the following is a proof of the earth's spherical shape?","images":[],"options":{"A":"Circum navigation","B":"Variations in the length of day and night","C":"Marking of a year","D":"Rise and fall of tides"},"answer":"A","explanation":"Circum navigation is the complete navigation around an entire island, continent or astronomical body(e.g a planet or moon)","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>32","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following types of rocks contain fossils?","images":[],"options":{"A":"Igneous","B":"Sedimentary","C":"Metamorphic","D":"Volcanic"},"answer":"B","explanation":"Sedimentary rock is the type of rock that typically contains fossils. They are formed from accumulation and compression of sediments such as mineral particles, organic matter and rock fragments e.g  of sedimentary rocks are shale, limestone, sandstone, conglomerate, mudstone","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>33","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The natural exchange of water between land, oceans and the atmosphere is known as the","images":[],"options":{"A":"energy cycle","B":"hydrological cycle","C":"nitrogen cycle","D":"carbon cycle"},"answer":"B","explanation":"The natural exchange of water between land, oceans and the atmosphere is known as the water cycle (also called the Hydrological cycle). It describes the continuous movement of water on, above and below the surface of the earth involving evaporation, condensation, precipitation, runoff, infiltration, transpiration. This constant exchange of water is essential for life on earth and helps regulate the planets climate and weather patterns.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>34","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Lines drawn on maps connecting places with equal duration of sunshine are called","images":[],"options":{"A":"isohels","B":"isotherms","C":"isonephs","D":"isohyets"},"answer":"A","explanation":"Isohels are lines on a map that connect point with equal values of a particular parameter, in this case, the duration of sunshine. These lines help visualize and analyze the distribution and sunshine hours across different regions. They are useful tools in geography, meterology to understand and represent various environmental phenomena.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>35","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following examples of rock is most likely to be weathered by the process of solution?","images":[],"options":{"A":"Slate","B":"Graphite","C":"Limestone","D":"Granite"},"answer":"C","explanation":"Limestone is a sedimentary rock composed primarily of calcium carbonate (CaCO3) from remains of marine organisms like coral and shells. Other rocks like dolostine, gypsum and halite are also susceptible to solution weathering but limestone is the most common example.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>36","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Which of the following occurs when the sun is vertically overhead at the equator?","images":[],"options":{"A":"Equinox","B":"Solstice","C":"Deflection of winds and ocean currents","D":"Rise and fall of tides"},"answer":"A","explanation":"This is when the sun is vertically overhead the equator, it is an indication of the equinox, which occurs twice a year.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>37","subject":"Geography","year":"2024","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which of the following pair of ways can be used to solve the world's high population concentration problems?  1.Family planning  II. Sex education  III. Early marriage  IV. Industrialization","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"III and IV only"},"answer":"A","explanation":"1.Family planning  II. Sex education  Industrialization can have both positive and negative effects on population growth but it is not a direct solution to high population concentration. Early marriage is actually a factor that can contribute to high population growth, as it can to early child bearing and more children so the correct pair is I and II that is family planning and sex education.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>38","subject":"Geography","year":"2024","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following countries in West Africa is well known for the production of diamonds?","images":[],"options":{"A":"Togo","B":"Burkina Faso","C":"Sierra Leone","D":"Benin"},"answer":"C","explanation":"Sierra Leone is a significant producer of diamonds in West Africa. The country has been known for its diamond production since the 1930s and diamonds have been a major contributor to its economy. Other options are well known for:  Togo: Known for phosphate and limestone production  Burkina faso: Known for its gold production  Benin: Known for its cotton and oil production  Serria Leone's diamond industry has faced challenges in the past, including the use of \"blood diamonds\" to fund conflicts. However, efforts have been made to improve the industry's transparency and ensure that diamond production benefit the country development.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>39","subject":"Geography","year":"2024","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following is a leading industrial area in North America?","images":[],"options":{"A":"The North Eastern industrial area of USA","B":"Central Canada industrial area","C":"South Mexico industrial area","D":"The Guatemala industrial area"},"answer":"A","explanation":"The North Eastern united states, particularly the region stretching from Boston to New York City, philadelphia, pittsburgh and detroil is a leading industrial area in North America.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>40","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"'It is an intensive cultivation of fruits, vegetables or flowers, it is small scale farming, the yields are very high per hectare, produce sold to customers are usually fresh and commonly practised in urban communities'. The above statements are characteristics of","images":[],"options":{"A":"mixed farming","B":"sericulture","C":"market gardening","D":"viniculture"},"answer":"C","explanation":"Market gardening is a type of intensive cultivation of fruits, vegetables and flowers characterized by small scale farming, high yield per hectare etc. Market gardening is a specialized form of agriculture that focuses on growing a wide variety of crops often using innovative techniques like hydroponics, green houses or vertical farming. Market gardening is a unique and specialized form of agriculture that fits the description provided.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>41","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"An advantage of large population is","images":[],"options":{"A":"increase in government expenditure","B":"surplus employment opportunities","C":"abundant labour force","D":"small market for goods"},"answer":"C","explanation":"A larger population can provide an abundant labour force which can be beneficial for economic growth and development.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>42","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT~~ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following best describes the relationship between rural and urban areas?","images":[],"options":{"A":"Urban areas are not as important as rural areas","B":"Urban areas and rural areas depend on each other","C":"Rural areas exist only to serve urban areas","D":"Urban areas can exist without rural areas"},"answer":"B","explanation":"This mutual dependence highlights the connectedness and interdependence of rural and urban areas.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>43","subject":"Geography","year":"2024","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which of the following factors has the greatest influence on the location of cement industry?","images":[],"options":{"A":"Proximity to source of raw materials","B":"Nearness to market","C":"Source of capital","D":"Manpower development"},"answer":"A","explanation":"The cement industry requires large quantities of raw materials such as limestone, clay. The cement industry typically locates near limestone quarries or other raw material source to minimize transportation cost and ensure a stable supply of raw materials.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2024>44","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following best describes high population growth?","images":[],"options":{"A":"Number of births equals number of deaths","B":"Birth rates are equal to death rates","C":"Emigration is equal to immigration","D":"Birth rates are higher than death rates"},"answer":"D","explanation":"High population growth occurs when the number of births(birth rate) exceeds the number of death(death rate) in a given population. This means that the population is increasing due to a natural increase in numbers rather than just for migration. High population growth is typically characterized by:  i. High birth rates(total fertility rate)  ii. Low death rates(due to improved health care, sanitation) etc. This leads to an increase in population size overtime.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>45","subject":"Geography","year":"2024","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which of the following pairs of activities can initiate deforestation?  I. Lumbering  II. Afforestation  III. Excavation  IV. Grazing","images":[],"options":{"A":"I and IV only","B":"II and III only","C":"II and IV only","D":"I and II only"},"answer":"A","explanation":"Lumbering: This is the harvesting of trees for wood, paper and other forest products can lead to deforestation if not done sustainably.  Grazing: Overgrazing by livestock can damage vegetable lead to soil erosion and create pathways for further deforestation.  NOTE: Other activities like agriculture, urbanization and infrastructure development can also lead to deforestation but among the given options lumbering and grazing are the most direct initiators.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>46","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE~~ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following is a major disadvantage of plantation agriculture?","images":[],"options":{"A":"Control weeds with herbicides","B":"Encourages monoculture","C":"Foreign exchange carner","D":"Application of modern technology"},"answer":"B","explanation":"Encouraging monoculture because using monoculture in plantain agriculture can result in the poliferation of pests and illness.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>47","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following is arranged according to increasing size of settlement?","images":[],"options":{"A":"Town, conurbation, hamlet and village","B":"Hamlet, village, town and conurbation","C":"Village, town, conurbation and hamlet","D":"Conurbation, town, hamlet and village"},"answer":"B","explanation":"The increasing order in size of settlement is Hamlet, village, town and conurbation. A hamlet is a small settlement that usually has only a few houses while a village is larger than a hamlet but smaller than a town. A conurbation is a region comprising a number of metropolises, cities, large town and other urban area which through population growth and physical expansion were merged to form one continuous urban or industrially developed area.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>48","subject":"Geography","year":"2024","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Wood carving, leatherwork and cloth weaving are examples of","images":[],"options":{"A":"chemical industry","B":"power industry","C":"heavy industry","D":"local craft industry"},"answer":"D","explanation":"This type of industry involves the production of goods using traditional methods and techniques that have been passed down through generations.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2024>49","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Population density is defined as the average","images":[],"options":{"A":"number of people in the capital towns","B":"number of people living in a unit area","C":"number of human resources","D":"number of deaths and births in a unit area"},"answer":"B","explanation":"The formular for calculating population density is Dp =  N/A. In this equation, Dp indicates the density of population, N is the total population as a number of people and A is the land area covered by that population.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2024>50","subject":"Geography","year":"2024","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A settlement pattern with houses arranged along lines of transportation is described as","images":[],"options":{"A":"dispersed","B":"linear","C":"radial","D":"nucleated"},"answer":"B","explanation":"A linear settlement is a (normally small to medium-sized) settlement or group of buildings that is formed in a long line many of these settlements are formed along a transport route, such as a road, river or canal.","marks":"1","difficulty":"3"}];